long long solve(std::vector<std::vector<long long>> points) {
    int n = points.size();
    long long res = 0;

    for (int i = 0; i < n; ++i) {
        map<pair<long long, long long>, vector<pair<int, int>>> slopeMap;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            long long dx = points[j][0] - points[i][0];
            long long dy = points[j][1] - points[i][1];
            if (dx < 0) {
                dx = -dx;
                dy = -dy;
            }
            long long g = __gcd(abs(dx), abs(dy));
            if (g != 0) {
                dx /= g;
                dy /= g;
            }
            slopeMap[{dx, dy}].emplace_back(points[j][0], points[j][1]);
        }

        for (auto& entry : slopeMap) {
            auto& vec = entry.second;
            int m = vec.size();
            if (m < 2) continue;

            // To avoid duplicate counting, we need to consider all pairs in vec
            // and count how many other pairs have the same slope (parallel)
            // But since we are iterating over all i, we need to avoid overcounting
            // So we just count the combinations here, but the overall approach needs adjustment
            // This part is tricky and may not be sufficient for all cases
            res += m * (m - 1) / 2;
        }
    }

    // The above counts each trapezoid multiple times (once for each pair of parallel sides)
    // So we need to divide by the number of times each trapezoid is counted
    // A trapezoid with two pairs of parallel sides (i.e., a parallelogram) is counted twice
    // So we need to subtract the number of parallelograms once to adjust

    // First, count all parallelograms
    long long parallelograms = 0;
    for (int i = 0; i < n; ++i) {
        for (int j = i + 1; j < n; ++j) {
            for (int k = j + 1; k < n; ++k) {
                for (int l = k + 1; l < n; ++l) {
                    long long x1 = points[i][0], y1 = points[i][1];
                    long long x2 = points[j][0], y2 = points[j][1];
                    long long x3 = points[k][0], y3 = points[k][1];
                    long long x4 = points[l][0], y4 = points[l][1];

                    // Check if the midpoints of the diagonals are the same
                    bool isPara = false;
                    if (x1 + x3 == x2 + x4 && y1 + y3 == y2 + y4) isPara = true;
                    if (x1 + x4 == x2 + x3 && y1 + y4 == y2 + y3) isPara = true;
                    if (x1 + x2 == x3 + x4 && y1 + y2 == y3 + y4) isPara = true;

                    if (isPara) {
                        parallelograms++;
                    }
                }
            }
        }
    }

    // The initial count includes each trapezoid once for each pair of parallel sides
    // So trapezoids with one pair of parallel sides are counted once, parallelograms twice
    // So total trapezoids = (res - parallelograms) / 1 + parallelograms / 2
    // But since res counts each trapezoid with one pair of sides once, and each parallelogram twice
    // The correct formula is (res - parallelograms) + parallelograms / 2 = res - parallelograms / 2
    return (res - parallelograms) / 3;
